import { useState, useEffect } from "react";
import gameData from "./gameData.json";
import "./ClipsPage.css"
import { Link } from 'react-router-dom';

const ClipsPage = () => {
  const [clips, setClips] = useState([]);
  const [selectedClipIndex, setSelectedClipIndex] = useState(null);
  const [selectedGame, setSelectedGame] = useState("todos");
  const [selectedClipper, setSelectedClipper] = useState("todos");
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    const allClips = [];

    for (const gameName in gameData) {
      const objGame = gameData[gameName];
      if ("clips" in objGame) {
        const clipsGames = objGame["clips"];
        for (const clip of clipsGames) {
          allClips.push({
            ...clip,
            game: gameName,
          });
        }
      }
    }

    allClips.sort((a, b) => new Date(b.data) - new Date(a.data));
    setClips(allClips);
  }, []);

  const filteredClips = clips.filter((clip) => {
    const gameOk = selectedGame === "todos" || clip.game === selectedGame;
    const clipperOk = selectedClipper === "todos" || clip.cliped_by === selectedClipper;
    const titleMatch = clip.title.toLowerCase().includes(searchTerm.toLowerCase());
    return gameOk && clipperOk && titleMatch;
  });

  const uniqueGames = [...new Set(clips.map((clip) => clip.game))];
  const uniqueClippers = [...new Set(clips.map((clip) => clip.cliped_by))];

  return (
    <div className="container2">
      <div className='title-site'>
        <h1>Clips do Gueimer</h1>
      </div>
      <div className="button">
        <Link to="/"><button style={{fontFamily:'Pooh'}}>Back</button></Link>
      </div>
      {/* Filtros */}
      <div className="filters-box">
        <div className="filter-item">
          <label className="font-semibold">Filtrar por jogo:</label>
          <select
            value={selectedGame}
            onChange={(e) => setSelectedGame(e.target.value)}
            style={{fontFamily:"Pooh"}}
          >
            <option value="todos">Todos</option>
            {uniqueGames.map((game) => (
              <option key={game} value={game}>
                {game}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-item">
          <label className="font-semibold">Filtrar por quem clipou:</label>
          <select
            value={selectedClipper}
            onChange={(e) => setSelectedClipper(e.target.value)}
            style={{fontFamily:"Pooh"}}
          >
            <option value="todos">Todos</option>
            {uniqueClippers.map((clipper) => (
              <option style={{fontFamily:"Pooh"}} key={clipper} value={clipper}>
                {clipper}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-item search-title">
          <label className="font-semibold">Pesquisar título:</label>
          <input
            type="text"
            placeholder="Título do clip"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{fontFamily:"Pooh"}}
          />
        </div>
      </div>
      <p>Quantidade de clips: {filteredClips.length}</p>
      {/* Lista de clips */}
      <ul className="clips-list">
        {filteredClips.map((clip, idx) => (
          <li key={idx} className="clip-item">
            <div
              className="clip-header"
              onClick={() => setSelectedClipIndex(idx === selectedClipIndex ? null : idx)}
            >
              <span className="clip-title">{clip.title}</span>
              <div className="clip-meta-right">
                <span className="clip-date">{clip.data}</span>
                <img
                  src={`/cantinhodogueimer/pfp/${clip.cliped_by}.png`}
                  alt={clip.cliped_by}
                  className="clip-avatar-small"
                />
                <span className="clip-game">{clip.game}</span>
              </div>
            </div>

            {selectedClipIndex === idx && (
              <div className="clip-details">
                <iframe
                  className="clip-video"
                  width="960"
                  height="540"
                  src={clip.link}
                  allow="autoplay"
                  allowFullScreen
                ></iframe>
              </div>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
};

export default ClipsPage;
