import React, { useState, useMemo } from 'react';
import Game from './Game';
import gameData from './gameData.json';
import { Link } from 'react-router-dom';
import './CantinhoDoGueimerPage.css';

// Helper functions
const getUniqueValues = (data, key) => {
    const values = new Set();
    Object.values(data).forEach(game => {
        if (Array.isArray(game[key])) {
            game[key].forEach(item => values.add(item));
        } else {
            values.add(game[key]);
        }
    });
    return Array.from(values).sort();
};

const getYearRange = (data) => {
    const years = Object.values(data).map(game => game.year);
    return [Math.min(...years), Math.max(...years)];
};

const CantinhoDoGueimerPage = () => {
    const [selectedGenre, setSelectedGenre] = useState('');
    const [selectedChosenBy, setSelectedChosenBy] = useState('');
    const [sortCriteria, setSortCriteria] = useState('date');

    // Calcular ano mínimo e máximo dos filmes
    const [minYear, maxYear] = useMemo(() => getYearRange(gameData), []);
    const [yearRange, setYearRange] = useState([minYear, maxYear]);

    const genres = useMemo(() => getUniqueValues(gameData, 'genres'), []);
    const chosenByPeople = useMemo(() => getUniqueValues(gameData, 'chosen by'), []);

    const compareDates = (game1, game2) => {
        const date1 = new Date(game1.date.split('/').reverse().join('-'));
        const date2 = new Date(game2.date.split('/').reverse().join('-'));
        return date2 - date1;
    };

    const compareRatings = (game1, game2) => {
        const getAverageRating = (game) => {
            if (game.reviews && typeof game.reviews === 'object') {
                const ratings = Object.values(game.reviews);
                if (ratings.length > 0) {
                    const totalRating = ratings.reduce((sum, rating) => sum + rating, 0);
                    return totalRating / ratings.length;
                }
            }
            return 0;
        };

        const avgRating1 = getAverageRating(game1);
        const avgRating2 = getAverageRating(game2);

        return avgRating2 - avgRating1;
    };

    const filteredGames = useMemo(() => {
        return Object.entries(gameData)
            .filter(([title, game]) => {
                const matchesGenre = selectedGenre ? game.genres.includes(selectedGenre) : true;
                const matchesChosenBy = selectedChosenBy ? game["chosen by"].includes(selectedChosenBy) : true;
                const matchesYear = game.year >= yearRange[0] && game.year <= yearRange[1];
                return matchesGenre && matchesChosenBy && matchesYear;
            })
            .sort(([, game1], [, game2]) => {
                if (sortCriteria === 'date') return compareDates(game1, game2);
                if (sortCriteria === 'rating') return compareRatings(game1, game2);
                if (sortCriteria === 'year') return game2.year - game1.year;
                return 0;
            });
    }, [selectedGenre, selectedChosenBy, yearRange, sortCriteria]);

    return (
        <div>
            <div className="title-site">
                <h1>Cantinho do Gueimer</h1>
            </div>
            <div className="button">
                <Link to="/stats"><button style={{fontFamily:'Pooh'}}>Stats</button></Link>
                <Link to="/guess"><button style={{fontFamily:'Pooh'}}>Guess Daily Game</button></Link>
                <Link to="/clips"><button style={{fontFamily:'Pooh'}}>Clips</button></Link>
            </div>

            {/* Filtros */}
            <div className="filters">
                <label>
                    Genre:
                    <select style={{fontFamily:'Pooh'}} value={selectedGenre} onChange={(e) => setSelectedGenre(e.target.value)}>
                        <option style={{fontFamily:'Pooh'}} value="">All</option>
                        {genres.map((genre, index) => (
                            <option style={{fontFamily:'Pooh'}} key={index} value={genre}>{genre}</option>
                        ))}
                    </select>
                </label>
                <label>
                    Recommendation by:
                    <select style={{fontFamily:'Pooh'}} value={selectedChosenBy} onChange={(e) => setSelectedChosenBy(e.target.value)}>
                        <option style={{fontFamily:'Pooh'}} value="">All</option>
                        {chosenByPeople.map((person, index) => (
                            <option style={{fontFamily:'Pooh'}} key={index} value={person}>{person}</option>
                        ))}
                    </select>
                </label>
                <label>
                    <div className="year-display">
                        <span>{yearRange[0]}</span>
                        <span>{yearRange[1]}</span>
                    </div>
                    Year:
                    {/* Slider inferior - controla o valor mínimo */}
                    <input
                        type="range"
                        min={minYear}
                        max={maxYear}
                        value={yearRange[0]}
                        onChange={(e) => {
                            const newMin = Number(e.target.value);
                            if (newMin <= yearRange[1]) {
                                setYearRange([newMin, yearRange[1]]);
                            }
                        }}
                    />
                    {/* Slider superior - controla o valor máximo */}
                    <input
                        type="range"
                        min={minYear}
                        max={maxYear}
                        value={yearRange[1]}
                        onChange={(e) => {
                            const newMax = Number(e.target.value);
                            if (newMax >= yearRange[0]) {
                                setYearRange([yearRange[0], newMax]);
                            }
                        }}
                    />
                </label>
                <label>
                    Sort by:
                    <select style={{fontFamily:'Pooh'}} value={sortCriteria} onChange={(e) => setSortCriteria(e.target.value)}>
                        <option style={{fontFamily:'Pooh'}} value="date">Date</option>
                        <option style={{fontFamily:'Pooh'}} value="rating">Average Rating</option>
                        <option style={{fontFamily:'Pooh'}} value="year">Year</option>
                    </select>
                </label>
            </div>

            {/* Catálogo de filmes */}
            <div className='catalog-page' style={{width:"100vw",height: "100vh!important"}}>
                {filteredGames.map(([title, game]) => (
                    <div className='game' key={title}>
                        <Game
                            key={title}
                            title={title}
                            year={game.year}
                            link={game.link}
                            date={game.date}
                            chosenBy={game["chosen by"]}
                            genres={game.genres}
                            reviews={game.reviews}
                            comments={game.comments}
                            nclips={game.clips.length}
                        />
                    </div>
                ))}
            </div>
        </div>
    );
}

export default CantinhoDoGueimerPage;
